class Solution {
public:
    int minDays(int n) {
        queue<int> q;
        q.push(n);
        int days = 0;
        unordered_set<int> visited;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int curr = q.front();
                q.pop();
                if (curr == 0) return days;
                if (curr - 1 > 0 && visited.find(curr - 1) == visited.end()) {
                    q.push(curr - 1);
                    visited.insert(curr - 1);
                }
                if (curr % 2 == 0 && curr - curr / 2 > 0 && visited.find(curr - curr / 2) == visited.end()) {
                    q.push(curr - curr / 2);
                    visited.insert(curr - curr / 2);
                }
                if (curr % 3 == 0 && curr - 2 * (curr / 3) > 0 && visited.find(curr - 2 * (curr / 3)) == visited.end()) {
                    q.push(curr - 2 * (curr / 3));
                    visited.insert(curr - 2 * (curr / 3));
                }
            }
            days++;
        }
        return -1;
    }
};
